USER_OPEN_INTERACTIVE_WINDOW = True
USER_INTERACTIVE_STEP = USER_TOTAL_ITERATIONS
USER_INTERACTIVE_ELEV_DEG = 0# 18.0
USER_INTERACTIVE_AZIM_DEG = 90# -58.0

